export function nextGeneration(cells: [number, number][]): [number, number][] {
  const key = (x: number, y: number): string => `${x},${y}`;
  const liveSet = new Set<string>(cells.map(([x, y]) => key(x, y)));

  const countLiveNeighbors = (x: number, y: number): number => {
    let count = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (liveSet.has(key(x + dx, y + dy))) count++;
      }
    }
    return count;
  };

  const result: [number, number][] = [];
  for (const [x, y] of cells) {
    const n = countLiveNeighbors(x, y);
    if (n === 2 || n === 3) result.push([x, y]);
  }
  return result;
}
